sql:
SELECT AVG(average_salary) AS average_salary
FROM job_industries
WHERE industry_name = 'Landscaping';

external_knowledge:
- "High demand" refers to the frequency of skills required in job postings;
- "Bloom" is a metaphor for the presence of a skill in a job posting;
- "Location" refers to the geographical area where the job postings are available.

sql:
SELECT 
  (
    SELECT COUNT(DISTINCT employer_id) FROM employers
  ) + (
    SELECT COUNT(DISTINCT posting_id) FROM job_postings
  ) + (
    SELECT COUNT(DISTINCT location_id) FROM locations
  ) + (
    SELECT COUNT(DISTINCT source_id) FROM sources
  ) + (
    SELECT COUNT(DISTINCT type_id) FROM job_types
  ) AS total_unique_entries;

external_knowledge:
